export function createMockTickData(
  startTick: number,
  endTick: number,
  steamIds: string[] = ["76561198000000001", "76561198000000002"],
): TickData[] {
  const data: TickData[] = []
  for (let t = startTick; t <= Math.min(endTick, startTick + 9); t++) {
    for (const sid of steamIds) {
      data.push({
        tick: t,
        steam_id: sid,
        x: t * 1.0,
        y: t * 2.0,
        z: 0,
        yaw: 90,
        health: 100,
        armor: 100,
        is_alive: true,
        weapon: "ak47",
        money: 0,
        has_helmet: false,
        has_defuser: false,
        inventory: [],
      })
    }
  }
  return data
}

